// nodes/mergeNode.js
import { BaseNode } from './BaseNode';
import { GitMerge } from 'lucide-react';

export const MergeNode = ({ id, data, selected }) => {
  return (
    <BaseNode
      id={id}
      title="Merge"
      icon={GitMerge}
      accentColor="var(--accent-emerald)"
      inputs={[
        { id: 'a', label: 'a' },
        { id: 'b', label: 'b' },
        { id: 'c', label: 'c' },
      ]}
      outputs={[{ id: 'merged', label: 'merged' }]}
      selected={selected}
    >
      <div style={{ fontSize: '13px', color: 'var(--text-secondary)' }}>
        <div style={{ display: 'flex', alignItems: 'center', gap: '6px', marginBottom: '4px' }}>
          <div style={{ width: 6, height: 6, borderRadius: '50%', background: 'var(--accent-emerald)' }} />
          <span style={{ fontWeight: 500, color: 'var(--text-primary)', textTransform: 'capitalize' }}>
            {data?.strategy || 'concat'}
          </span>
        </div>
      </div>
    </BaseNode>
  );
};
